"use strict";var e={invoke:async(e,o)=>{const{name:r}=e;if(!r)throw new Error("Missing required parameter: name");const msg=`Hello, ${r}!`;console.log(msg);return{message:msg,timestamp:new Date().toISOString()}},error:async(e)=>{const{error:o}=e;if(o&&o.message&&o.message.includes("recoverable"))return{recovered:true};throw new Error(`Unrecoverable: ${o?o.message:"unknown"}`)},halt:async(e)=>{console.log("Halting");return undefined}};module.exports=e;
